	private GenericPlanNode buildPlanNode(QueryModelNode node, Set<String> incomingBindings) {
		GenericPlanNode genericPlanNode = new GenericPlanNode(getNodeSignature(node));
		genericPlanNode.setCostEstimate(node.getCostEstimate());
		genericPlanNode.setResultSizeEstimate(node.getResultSizeEstimate());
		genericPlanNode.setResultSizeActual(node.getResultSizeActual());
		genericPlanNode.setHasNextCallCountActual(runtimeTelemetryMetric(node.getHasNextCallCountActual()));
		genericPlanNode.setHasNextTrueCountActual(runtimeTelemetryMetric(node.getHasNextTrueCountActual()));
		genericPlanNode.setHasNextTimeNanosActual(runtimeTelemetryMetric(node.getHasNextTimeNanosActual()));
		genericPlanNode.setNextCallCountActual(runtimeTelemetryMetric(node.getNextCallCountActual()));
		genericPlanNode.setNextTimeNanosActual(runtimeTelemetryMetric(node.getNextTimeNanosActual()));
		genericPlanNode
				.setJoinRightIteratorsCreatedActual(runtimeTelemetryMetric(node.getJoinRightIteratorsCreatedActual()));
		genericPlanNode
				.setJoinLeftBindingsConsumedActual(runtimeTelemetryMetric(node.getJoinLeftBindingsConsumedActual()));
		genericPlanNode
				.setJoinRightBindingsConsumedActual(runtimeTelemetryMetric(node.getJoinRightBindingsConsumedActual()));
		genericPlanNode.setSourceRowsScannedActual(runtimeTelemetryMetric(node.getSourceRowsScannedActual()));
		genericPlanNode.setSourceRowsMatchedActual(runtimeTelemetryMetric(node.getSourceRowsMatchedActual()));
		genericPlanNode.setSourceRowsFilteredActual(runtimeTelemetryMetric(node.getSourceRowsFilteredActual()));
		if (level.includesRuntimeTelemetry()) {
			genericPlanNode.setLongMetricsActual(new LinkedHashMap<>(node.getLongMetricsActual()));
			genericPlanNode.setDoubleMetricsActual(new LinkedHashMap<>(node.getDoubleMetricsActual()));
			genericPlanNode.setStringMetricsActual(new LinkedHashMap<>(node.getStringMetricsActual()));
			applyVariableShapeMetrics(node, genericPlanNode);
		}
		if (level.includesEvaluationAnnotations()) {
			applyExplainAnnotations(node, genericPlanNode, incomingBindings);
		}
		if (node instanceof VariableScopeChange) {
			genericPlanNode.setNewScope(((VariableScopeChange) node).isVariableScopeChange());
		}
		if (node instanceof BinaryTupleOperator) {
			genericPlanNode.setAlgorithm(((BinaryTupleOperator) node).getAlgorithmName());
		}
		genericPlanNode.setTotalTimeActual(node.getTotalTimeNanosActual() / 1_000_000.0);

		for (QueryModelNode child : directChildren(node)) {
			genericPlanNode.addPlans(buildPlanNode(child, childIncomingBindings(node, child, incomingBindings)));
		}

		return genericPlanNode;
	}

	private String getNodeSignature(QueryModelNode node) {
		if (!namespacePrefixes.isEmpty() && node instanceof Var) {
			Var var = (Var) node;
			Value value = var.getValue();
			if (value instanceof IRI) {
				String prefixed = toPrefixedName((IRI) value);
				if (prefixed != null) {
					StringBuilder sb = new StringBuilder(64);
					sb.append("Var");
					sb.append(" (name=").append(var.getName());
					sb.append(", value=").append(prefixed);
					if (var.isAnonymous()) {
						sb.append(", anonymous");
					}
					sb.append(")");
					return sb.toString();
				}
			}
		}
		return node.getSignature();
	}

	private String toPrefixedName(IRI iri) {
		String iriString = iri.stringValue();
		for (Map.Entry<String, String> entry : namespacePrefixes.entrySet()) {
			String namespace = entry.getKey();
			if (iriString.startsWith(namespace)) {
				String localName = iriString.substring(namespace.length());
				if (!localName.isEmpty() && isValidLocalName(localName)) {
					return entry.getValue() + ":" + localName;
				}
			}
		}
		return null;
	}

	private static boolean isValidLocalName(String localName) {
		for (int i = 0; i < localName.length(); i++) {
			char c = localName.charAt(i);
			if (c == '/' || c == '#' || c == '?' || c == '&' || c == ' ') {
				return false;
			}
		}
		return true;
	}

	private long runtimeTelemetryMetric(long value) {
		if (level.includesRuntimeTelemetry()) {
			return Math.max(0, value);
		}
		return -1;
	}

	private static Explanation.Level defaultExplanationLevel(QueryModelNode node) {
		return node != null && node.isRuntimeTelemetryEnabled()
				? Explanation.Level.Telemetry
				: Explanation.Level.Executed;
	}

	private static void applyVariableShapeMetrics(QueryModelNode node, GenericPlanNode genericPlanNode) {
		if (!(node instanceof TupleExpr)) {
			return;
		}

		TupleExpr tupleExpr = (TupleExpr) node;
		Set<String> outputBindings = new LinkedHashSet<>(tupleExpr.getBindingNames());
		Set<String> inputBindings = inputBindingNames(tupleExpr);
		if (inputBindings.isEmpty() && outputBindings.isEmpty()) {
			return;
		}

		long varsAdded = outputBindings.stream()
				.filter(binding -> !inputBindings.contains(binding))
				.count();
		long varsDropped = inputBindings.stream()
				.filter(binding -> !outputBindings.contains(binding))
				.count();

		if (varsAdded > 0) {
			genericPlanNode.setLongMetricActual(TelemetryMetricNames.VARS_ADDED_ACTUAL, varsAdded);
			genericPlanNode.setStringMetricActual(
					TelemetryMetricNames.METRIC_ORIGIN + "." + TelemetryMetricNames.VARS_ADDED_ACTUAL,
					"derived");
		}
		if (varsDropped > 0) {
			genericPlanNode.setLongMetricActual(TelemetryMetricNames.VARS_DROPPED_ACTUAL, varsDropped);
			genericPlanNode.setStringMetricActual(
					TelemetryMetricNames.METRIC_ORIGIN + "." + TelemetryMetricNames.VARS_DROPPED_ACTUAL,
					"derived");
		}
	}

	private static Set<String> inputBindingNames(TupleExpr tupleExpr) {
		Set<String> inputBindings = new LinkedHashSet<>();
		if (tupleExpr instanceof UnaryTupleOperator) {
			inputBindings.addAll(((UnaryTupleOperator) tupleExpr).getArg().getBindingNames());
			return inputBindings;
		}
		if (tupleExpr instanceof BinaryTupleOperator) {
			BinaryTupleOperator binary = (BinaryTupleOperator) tupleExpr;
			inputBindings.addAll(binary.getLeftArg().getBindingNames());
			inputBindings.addAll(binary.getRightArg().getBindingNames());
		}
		return inputBindings;
	}

	private void applyExplainAnnotations(QueryModelNode node, GenericPlanNode genericPlanNode,
			Set<String> incomingBindings) {
		if (node instanceof Var) {
			Var var = (Var) node;
			if (!var.isConstant()) {
				genericPlanNode.setStringMetricActual(TelemetryMetricNames.BINDING_STATE,
						incomingBindings.contains(var.getName()) ? "bound" : "unbound");
			}
		}

		if (node instanceof StatementPattern) {
			applyIndexAnnotation((StatementPattern) node, genericPlanNode);
		}

		if (cartesianJoinExplainAnalyzer != null) {
			String joinType = cartesianJoinExplainAnalyzer.getJoinType(node);
			if (joinType != null) {
				genericPlanNode.setStringMetricActual(TelemetryMetricNames.JOIN_TYPE, joinType);
			}
		}
	}

	private static void applyIndexAnnotation(StatementPattern statementPattern, GenericPlanNode genericPlanNode) {
		String indexName = statementPattern.getIndexName();
		if (indexName == null || indexName.isEmpty()) {
			return;
		}
		if (indexName.contains(",")) {
			genericPlanNode.setStringMetricActual(TelemetryMetricNames.INDEX_NAMES, indexName);
		} else {
			genericPlanNode.setStringMetricActual(TelemetryMetricNames.INDEX_NAME, indexName);
		}
	}

	private Set<String> childIncomingBindings(QueryModelNode parent, QueryModelNode child,
			Set<String> incomingBindings) {
		if (parent instanceof BinaryTupleOperator && child == ((BinaryTupleOperator) parent).getRightArg()) {
			return rightIncomingBindings((BinaryTupleOperator) parent, incomingBindings);
		}
		if (parent instanceof Filter && child == ((Filter) parent).getCondition()) {
			return union(incomingBindings, ((Filter) parent).getArg().getBindingNames());
		}
		if (parent instanceof LeftJoin && child == ((LeftJoin) parent).getCondition()) {
			LeftJoin leftJoin = (LeftJoin) parent;
			return union(incomingBindings, leftJoin.getLeftArg().getBindingNames(),
					leftJoin.getRightArg().getBindingNames());
		}
		if (parent instanceof Projection && child == ((Projection) parent).getProjectionElemList()) {
			return union(incomingBindings, ((Projection) parent).getArg().getBindingNames());
		}
		if (parent instanceof Extension && child instanceof ExtensionElem) {
			return incomingBindingsForExtensionElem((Extension) parent, (ExtensionElem) child, incomingBindings);
		}
		if (parent instanceof Group && child instanceof GroupElem) {
			Group group = (Group) parent;
			return union(incomingBindings, group.getArg().getBindingNames(), group.getGroupBindingNames());
		}
		if (parent instanceof OrderElem) {
			return incomingBindings;
		}
		return incomingBindings;
	}

	private Set<String> incomingBindingsForExtensionElem(Extension extension, ExtensionElem extensionElem,
			Set<String> incomingBindings) {
		Set<String> visibleBindings = union(incomingBindings, extension.getArg().getBindingNames());
		for (ExtensionElem element : extension.getElements()) {
			if (element == extensionElem) {
				break;
			}
			visibleBindings.add(element.getName());
		}
		return visibleBindings;
	}

	private Set<String> rightIncomingBindings(BinaryTupleOperator parent, Set<String> incomingBindings) {
		if (!(parent instanceof Join || parent instanceof LeftJoin)) {
			return incomingBindings;
		}
		String algorithmName = parent.getAlgorithmName();
		if (algorithmName == null || algorithmName.isEmpty()) {
			return union(incomingBindings, parent.getLeftArg().getBindingNames());
		}
		if (INCOMING_ONLY_RIGHT_ALGORITHMS.contains(algorithmName)) {
			return incomingBindings;
		}
		if (LEFT_BOUND_RIGHT_ALGORITHMS.contains(algorithmName)) {
			return union(incomingBindings, parent.getLeftArg().getBindingNames());
		}
		return incomingBindings;
	}

	private static Set<String> union(Set<String> incomingBindings, Set<String> additionalBindings) {
		Set<String> union = new LinkedHashSet<>(incomingBindings);
		union.addAll(additionalBindings);
		return union;
	}

	private static Set<String> union(Set<String> incomingBindings, Set<String> additionalBindings,
			Set<String> moreBindings) {
		Set<String> union = union(incomingBindings, additionalBindings);
		union.addAll(moreBindings);
		return union;
	}

	private static List<QueryModelNode> directChildren(QueryModelNode node) {
		DirectChildCollector collector = new DirectChildCollector();
		node.visitChildren(collector);
		return collector.children;
	}

	private static final class DirectChildCollector extends AbstractQueryModelVisitor<RuntimeException> {

		private final List<QueryModelNode> children = new ArrayList<>();

		@Override
		protected void meetNode(QueryModelNode node) {
			children.add(node);
		}
	}
